count = 0
total = 0
max_score = None
min_score = None

while True:
    score = eval(input("请输入成绩（负数结束）："))
    if score < 0:
        break
    count += 1
    total += score
    if max_score is None or score > max_score:
        max_score = score
    if min_score is None or score < min_score:
        min_score = score

if count == 0:
    print("没有输入成绩")
else:
    print("最高分：", max_score)
    print("最低分：", min_score)
    print("平均分：{:.2f}".format(total / count))

